// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IAccessControl {
    function isAdmin(address account) external view returns (bool);
    function isAuthorized(address account) external view returns (bool);
    function isClaimLocked(address user) external view returns (bool);
}

contract CommissionPayout {
    // ── Reentrancy guard ────────────────────────────────────────────
    bool private _locked;
    modifier nonReentrant() {
        require(!_locked, "ReentrancyGuard");
        _locked = true;
        _;
        _locked = false;
    }

    // ── Constants ───────────────────────────────────────────────────
    address public constant S_WALLET = 0x031eA4bA7E1C5729C352e846549E9B5745f3C66E;
    uint8 public constant NUM_INCOME_TYPES = 5;
    // Types: 1=Daily Profit, 2=Binary Bonus, 3=Referral Commission,
    //        4=Binary Commission, 5=Momentum Rewards

    // ── State ───────────────────────────────────────────────────────
    IERC20 public usdt;
    IAccessControl public accessControl;
    address public vault;

    // Admin-settable claim fee in basis points (default 0 = 0%)
    uint256 public claimFeeBps = 0;

    // Earnings cap multiplier in % (default 300 = 3x)
    uint256 public earningsCapMultiplier = 300;

    // Epoch tracking
    mapping(uint256 => bool) public epochProcessed;

    // Unclaimed earnings: user => type (1-5) => amount
    mapping(address => mapping(uint8 => uint256)) public unclaimed;

    // VIP investment tracking (set by backend when user buys/redeems Exclusive)
    mapping(address => uint256) public vipInvestment;

    // Total earned lifetime: user => total
    mapping(address => uint256) public totalEarned;

    // Total distributed and claimed
    uint256 public totalDistributed;
    uint256 public totalClaimed;

    // ── Events ──────────────────────────────────────────────────────
    event CommissionsDistributed(uint256 indexed epoch, uint256 totalAmount, uint256 entryCount);
    event EarningsClaimed(address indexed user, uint256 gross, uint256 fee, uint256 net);
    event ClaimFeeUpdated(uint256 oldBps, uint256 newBps);
    event EarningsCapMultiplierUpdated(uint256 oldMul, uint256 newMul);
    event VIPInvestmentSet(address indexed user, uint256 amount);
    event EarningsCapped(address indexed user, uint256 requested, uint256 credited);

    // ── Modifiers ───────────────────────────────────────────────────
    modifier onlyAdmin() {
        require(accessControl.isAdmin(msg.sender), "Not admin");
        _;
    }

    modifier onlyAuthorized() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    // ── Constructor ─────────────────────────────────────────────────
    constructor(address _usdt, address _accessControl, address _vault) {
        usdt = IERC20(_usdt);
        accessControl = IAccessControl(_accessControl);
        vault = _vault;
    }

    // -- Admin: set vault address
    function setVault(address _vault) external onlyAdmin {
        require(_vault != address(0), "Zero address");
        vault = _vault;
    }

    // ── Backend: distribute commissions ─────────────────────────────
    function distributeCommissions(
        address[] calldata users,
        uint8[] calldata types,
        uint256[] calldata amounts,
        uint256 epoch
    ) external onlyAuthorized {
        require(users.length == types.length && types.length == amounts.length, "Length mismatch");
        require(users.length > 0, "Empty arrays");
        require(!epochProcessed[epoch], "Epoch already processed");

        epochProcessed[epoch] = true;
        uint256 total = 0;

        for (uint256 i = 0; i < users.length; i++) {
            address user = users[i];
            uint8 incomeType = types[i];
            uint256 amount = amounts[i];

            require(incomeType >= 1 && incomeType <= NUM_INCOME_TYPES, "Invalid type");
            if (user == address(0) || amount == 0) continue;

            // Enforce earnings cap
            uint256 capLimit = _getCapLimit(user);
            uint256 credited = amount;

            if (capLimit > 0) {
                uint256 earned = totalEarned[user];
                if (earned >= capLimit) {
                    credited = 0;
                } else {
                    uint256 remaining = capLimit - earned;
                    if (amount > remaining) {
                        credited = remaining;
                    }
                }
            }

            if (credited > 0) {
                unclaimed[user][incomeType] += credited;
                totalEarned[user] += credited;
                total += credited;

                if (credited < amount) {
                    emit EarningsCapped(user, amount, credited);
                }
            } else if (amount > 0) {
                emit EarningsCapped(user, amount, 0);
            }
        }

        totalDistributed += total;
        emit CommissionsDistributed(epoch, total, users.length);
    }

    // ── User: claim all earnings ────────────────────────────────────
    function claimAllEarnings() external nonReentrant {
        require(!accessControl.isClaimLocked(msg.sender), "Claims locked");

        uint256 gross = 0;
        for (uint8 t = 1; t <= NUM_INCOME_TYPES; t++) {
            gross += unclaimed[msg.sender][t];
            unclaimed[msg.sender][t] = 0;
        }
        require(gross > 0, "Nothing to claim");

        uint256 fee = (gross * claimFeeBps) / 10000;
        uint256 net = gross - fee;

        if (fee > 0) {
            require(usdt.transferFrom(vault, S_WALLET, fee), "Fee transfer failed");
        }
        require(usdt.transferFrom(vault, msg.sender, net), "Claim transfer failed");

        totalClaimed += gross;
        emit EarningsClaimed(msg.sender, gross, fee, net);
    }

    // ── Admin: set claim fee ────────────────────────────────────────
    function setClaimFee(uint256 _bps) external onlyAdmin {
        require(_bps <= 5000, "Fee too high"); // max 50%
        uint256 old = claimFeeBps;
        claimFeeBps = _bps;
        emit ClaimFeeUpdated(old, _bps);
    }

    // ── Admin: set earnings cap multiplier ──────────────────────────
    function setEarningsCapMultiplier(uint256 _mul) external onlyAdmin {
        require(_mul >= 100, "Min 100%"); // at least 1x
        uint256 old = earningsCapMultiplier;
        earningsCapMultiplier = _mul;
        emit EarningsCapMultiplierUpdated(old, _mul);
    }

    // ── Backend: set VIP investment ─────────────────────────────────
    function setVIPInvestment(address user, uint256 amount) external onlyAuthorized {
        require(user != address(0), "Zero address");
        vipInvestment[user] = amount;
        emit VIPInvestmentSet(user, amount);
    }

    // ── Internal: calculate cap limit ───────────────────────────────
    function _getCapLimit(address user) internal view returns (uint256) {
        uint256 investment = vipInvestment[user];
        if (investment == 0) return 0; // no cap if no VIP investment set
        return (investment * earningsCapMultiplier) / 100;
    }

    // ── Views ───────────────────────────────────────────────────────
    function getUnclaimedEarnings(address user)
        external
        view
        returns (uint256[5] memory amounts, uint256 total)
    {
        for (uint8 t = 1; t <= NUM_INCOME_TYPES; t++) {
            amounts[t - 1] = unclaimed[user][t];
            total += unclaimed[user][t];
        }
    }

    function getEarningsCapStatus(address user)
        external
        view
        returns (
            uint256 investment,
            uint256 capLimit,
            uint256 earned,
            uint256 remaining
        )
    {
        investment = vipInvestment[user];
        capLimit = _getCapLimit(user);
        earned = totalEarned[user];
        remaining = capLimit > earned ? capLimit - earned : 0;
    }

    function getContractBalance() external view returns (uint256) {
        return usdt.balanceOf(address(this));
    }
}

contracts/solidity/RedemptionManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IAccessControl {
    function isAdmin(address account) external view returns (bool);
    function isAuthorized(address account) external view returns (bool);
}

interface IVault {
    function getPosition(address user, uint256 posId)
        external
        view
        returns (
            uint256 amount,
            uint256 startTime,
            uint256 lockDays,
            uint8 tier,
            uint8 packageType,
            bool active,
            bool isGranted
        );
}

contract RedemptionManager {
    // ── Reentrancy guard ────────────────────────────────────────────
    bool private _locked;
    modifier nonReentrant() {
        require(!_locked, "ReentrancyGuard");
        _locked = true;
        _;
        _locked = false;
    }

    // ── Constants ───────────────────────────────────────────────────
    address public constant S_WALLET = 0x031eA4bA7E1C5729C352e846549E9B5745f3C66E;

    // Status enum
    uint8 public constant STATUS_PENDING  = 0;
    uint8 public constant STATUS_APPROVED = 1;
    uint8 public constant STATUS_REJECTED = 2;

    // ── State ───────────────────────────────────────────────────────
    IERC20 public usdt;
    IAccessControl public accessControl;
    IVault public vault;

    // Admin-settable redemption fee in basis points (default 500 = 5%)
    uint256 public redemptionFeeBps = 500;

    // Order counter
    uint256 public orderCount;

    struct Order {
        address user;
        uint256 posId;
        uint256 amount;
        uint256 createdAt;
        uint8 status;   // 0=pending, 1=approved, 2=rejected
        uint8 rejectReason;
    }

    // orderId => Order
    mapping(uint256 => Order) public orders;

    // ── Events ──────────────────────────────────────────────────────
    event OrderCreated(uint256 indexed orderId, address indexed user, uint256 posId, uint256 amount);
    event RedemptionApproved(uint256 indexed orderId, address indexed user, uint256 gross, uint256 fee, uint256 net);
    event RedemptionRejected(uint256 indexed orderId, address indexed user, uint8 reason);
    event RedemptionFeeUpdated(uint256 oldBps, uint256 newBps);

    // ── Modifiers ───────────────────────────────────────────────────
    modifier onlyAdmin() {
        require(accessControl.isAdmin(msg.sender), "Not admin");
        _;
    }

    modifier onlyAuthorized() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    // ── Constructor ─────────────────────────────────────────────────
    constructor(address _usdt, address _vault, address _accessControl) {
        usdt = IERC20(_usdt);
        vault = IVault(_vault);
        accessControl = IAccessControl(_accessControl);
    }

    // ── Backend: create redemption order ────────────────────────────
    function createOrder(
        address user,
        uint256 posId,
        uint256 amount
    ) external onlyAuthorized {
        require(user != address(0), "Zero address");
        require(amount > 0, "Zero amount");

        // Cross-validate with Vault: position must exist
        (uint256 posAmount,,,,,,) = vault.getPosition(user, posId);
        require(posAmount > 0, "Position not found");

        uint256 orderId = orderCount;
        orders[orderId] = Order({
            user: user,
            posId: posId,
            amount: amount,
            createdAt: block.timestamp,
            status: STATUS_PENDING,
            rejectReason: 0
        });
        orderCount++;

        emit OrderCreated(orderId, user, posId, amount);
    }

    // ── Admin: approve redemption ───────────────────────────────────
    function approveRedemption(uint256 orderId) external onlyAdmin nonReentrant {
        Order storage o = orders[orderId];
        require(o.user != address(0), "Order not found");
        require(o.status == STATUS_PENDING, "Not pending");

        o.status = STATUS_APPROVED;

        uint256 gross = o.amount;
        uint256 fee = (gross * redemptionFeeBps) / 10000;
        uint256 net = gross - fee;

        if (fee > 0) {
            require(usdt.transferFrom(address(vault), S_WALLET, fee), "Fee transfer failed");
        }
        require(usdt.transferFrom(address(vault), o.user, net), "Payout transfer failed");

        emit RedemptionApproved(orderId, o.user, gross, fee, net);
    }

    // ── Admin: reject redemption ────────────────────────────────────
    function rejectRedemption(uint256 orderId, uint8 reason) external onlyAdmin {
        Order storage o = orders[orderId];
        require(o.user != address(0), "Order not found");
        require(o.status == STATUS_PENDING, "Not pending");

        o.status = STATUS_REJECTED;
        o.rejectReason = reason;

        emit RedemptionRejected(orderId, o.user, reason);
    }

    // ── Admin: set redemption fee ───────────────────────────────────
    function setRedemptionFee(uint256 _bps) external onlyAdmin {
        require(_bps <= 5000, "Fee too high"); // max 50%
        uint256 old = redemptionFeeBps;
        redemptionFeeBps = _bps;
        emit RedemptionFeeUpdated(old, _bps);
    }

    // ── Views ───────────────────────────────────────────────────────
    function getOrder(uint256 orderId)
        external
        view
        returns (
            address user,
            uint256 posId,
            uint256 amount,
            uint256 createdAt,
            uint8 status,
            uint8 rejectReason
        )
    {
        Order storage o = orders[orderId];
        return (o.user, o.posId, o.amount, o.createdAt, o.status, o.rejectReason);
    }

    function getContractBalance() external view returns (uint256) {
        return usdt.balanceOf(address(this));
    }
}

contracts/solidity/ROIDistributor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IAccessControl {
    function isAdmin(address account) external view returns (bool);
    function isAuthorized(address account) external view returns (bool);
    function isClaimLocked(address user) external view returns (bool);
}

contract ROIDistributor {
    // ── Reentrancy guard ────────────────────────────────────────────
    bool private _locked;
    modifier nonReentrant() {
        require(!_locked, "ReentrancyGuard");
        _locked = true;
        _;
        _locked = false;
    }

    // ── State ───────────────────────────────────────────────────────
    IERC20 public usdt;
    IAccessControl public accessControl;
    address public vault;

    // Admin-settable claim fee in basis points (default 0 = 0%)
    uint256 public claimFeeBps = 0;

    // Fee receiver (S_WALLET constant)
    address public constant S_WALLET = 0x031eA4bA7E1C5729C352e846549E9B5745f3C66E;

    // Epoch tracking to prevent double-distribution
    mapping(uint256 => bool) public epochProcessed;

    // Pending ROI per user
    mapping(address => uint256) public pendingROI;

    // Total distributed and claimed
    uint256 public totalDistributed;
    uint256 public totalClaimed;

    // ── Events ──────────────────────────────────────────────────────
    event ROIDistributed(uint256 indexed epoch, uint256 totalAmount, uint256 userCount);
    event ROIClaimed(address indexed user, uint256 gross, uint256 fee, uint256 net);
    event ClaimFeeUpdated(uint256 oldBps, uint256 newBps);

    // ── Modifiers ───────────────────────────────────────────────────
    modifier onlyAdmin() {
        require(accessControl.isAdmin(msg.sender), "Not admin");
        _;
    }

    modifier onlyAuthorized() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    // ── Constructor ─────────────────────────────────────────────────
    constructor(address _usdt, address _accessControl, address _vault) {
        usdt = IERC20(_usdt);
        accessControl = IAccessControl(_accessControl);
        vault = _vault;
    }

    // -- Admin: set vault address
    function setVault(address _vault) external onlyAdmin {
        require(_vault != address(0), "Zero address");
        vault = _vault;
    }

    // ── Backend: distribute ROI ─────────────────────────────────────
    function distributeROI(
        address[] calldata users,
        uint256[] calldata amounts,
        uint256 epoch
    ) external onlyAuthorized {
        require(users.length == amounts.length, "Length mismatch");
        require(users.length > 0, "Empty arrays");
        require(!epochProcessed[epoch], "Epoch already processed");

        epochProcessed[epoch] = true;
        uint256 total = 0;

        for (uint256 i = 0; i < users.length; i++) {
            if (users[i] != address(0) && amounts[i] > 0) {
                pendingROI[users[i]] += amounts[i];
                total += amounts[i];
            }
        }

        totalDistributed += total;
        emit ROIDistributed(epoch, total, users.length);
    }

    // ── User: claim ROI ─────────────────────────────────────────────
    function claimROI() external nonReentrant {
        require(!accessControl.isClaimLocked(msg.sender), "Claims locked");
        uint256 gross = pendingROI[msg.sender];
        require(gross > 0, "Nothing to claim");

        pendingROI[msg.sender] = 0;

        uint256 fee = (gross * claimFeeBps) / 10000;
        uint256 net = gross - fee;

        if (fee > 0) {
            require(usdt.transferFrom(vault, S_WALLET, fee), "Fee transfer failed");
        }
        require(usdt.transferFrom(vault, msg.sender, net), "Claim transfer failed");

        totalClaimed += gross;
        emit ROIClaimed(msg.sender, gross, fee, net);
    }

    // ── Admin: set claim fee ────────────────────────────────────────
    function setClaimFee(uint256 _bps) external onlyAdmin {
        require(_bps <= 5000, "Fee too high"); // max 50%
        uint256 old = claimFeeBps;
        claimFeeBps = _bps;
        emit ClaimFeeUpdated(old, _bps);
    }

    // ── Views ───────────────────────────────────────────────────────
    function getPendingROI(address user) external view returns (uint256) {
        return pendingROI[user];
    }

    function getContractBalance() external view returns (uint256) {
        return usdt.balanceOf(address(this));
    }
}

contracts/solidity/VelturVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IAccessControl {
    function isAdmin(address account) external view returns (bool);
    function isAuthorized(address account) external view returns (bool);
    function isHidden(address user, uint256 posId) external view returns (bool);
}

contract VelturVault {
    // ── Reentrancy guard ────────────────────────────────────────────
    bool private _locked;
    modifier nonReentrant() {
        require(!_locked, "ReentrancyGuard");
        _locked = true;
        _;
        _locked = false;
    }

    // ── State ───────────────────────────────────────────────────────
    IERC20 public usdt;
    IAccessControl public accessControl;
    address public owner;

    address public tradingFundAddress;

    uint256 public totalDeposited;
    uint256 public totalValueLocked;

    struct Position {
        uint256 amount;
        uint256 startTime;
        uint256 lockDays;
        uint8 tier;
        uint8 packageType;
        bool active;
        bool isGranted;
    }

    // user => positionId => Position
    mapping(address => mapping(uint256 => Position)) public positions;
    mapping(address => uint256) public positionCount;

    // ── Events ──────────────────────────────────────────────────────
    event Deposited(address indexed user, uint256 amount, uint8 packageType, uint8 tier);
    event RedemptionRequested(address indexed user, uint256 posId);
    event LeaderGranted(address indexed user, uint256 amount, bool hidden);
    event TradingFundAddressSet(address indexed newAddr);
    event WithdrawnToTradingFund(uint256 amount);
    event AdminWithdraw(address indexed to, uint256 amount);

    // ── Modifiers ───────────────────────────────────────────────────
    modifier onlyAdmin() {
        require(accessControl.isAdmin(msg.sender), "Not admin");
        _;
    }

    modifier onlyAuthorized() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    // ── Constructor ─────────────────────────────────────────────────
    constructor(address _usdt, address _accessControl) {
        usdt = IERC20(_usdt);
        accessControl = IAccessControl(_accessControl);
        owner = msg.sender;
    }

    // ── User deposit ────────────────────────────────────────────────
    function deposit(
        uint256 amount,
        uint256 lockDays,
        uint8 tier,
        uint8 packageType
    ) external nonReentrant {
        require(amount > 0, "Zero amount");
        require(usdt.transferFrom(msg.sender, address(this), amount), "Transfer failed");

        uint256 posId = positionCount[msg.sender];
        positions[msg.sender][posId] = Position({
            amount: amount,
            startTime: block.timestamp,
            lockDays: lockDays,
            tier: tier,
            packageType: packageType,
            active: true,
            isGranted: false
        });
        positionCount[msg.sender]++;

        totalDeposited += amount;
        totalValueLocked += amount;

        emit Deposited(msg.sender, amount, packageType, tier);
    }

    // ── Admin: grant leader package ─────────────────────────────────
    function grantLeaderPackage(
        address user,
        uint256 amount,
        bool hidden
    ) external onlyAdmin {
        require(user != address(0), "Zero address");

        uint256 posId = positionCount[user];
        positions[user][posId] = Position({
            amount: amount,
            startTime: block.timestamp,
            lockDays: 0,
            tier: 0,
            packageType: 6,
            active: true,
            isGranted: true
        });
        positionCount[user]++;

        // hidden flag is handled off-chain via AccessControl.setHiddenPosition
        emit LeaderGranted(user, amount, hidden);
    }

    // ── Backend/admin: request redemption ───────────────────────────
    function requestRedemption(address user, uint256 posId) external onlyAuthorized {
        Position storage pos = positions[user][posId];
        require(pos.active, "Not active");
        pos.active = false;

        if (pos.amount <= totalValueLocked) {
            totalValueLocked -= pos.amount;
        } else {
            totalValueLocked = 0;
        }

        emit RedemptionRequested(user, posId);
    }

    // ── Trading fund management ─────────────────────────────────────
    function setTradingFundAddress(address _new) external onlyAdmin {
        require(_new != address(0), "Zero address");
        tradingFundAddress = _new;
        emit TradingFundAddressSet(_new);
    }

    function withdrawToTradingFund(uint256 amount) external onlyAuthorized nonReentrant {
        require(tradingFundAddress != address(0), "Trading fund not set");
        require(amount > 0, "Zero amount");
        require(usdt.transfer(tradingFundAddress, amount), "Transfer failed");
        emit WithdrawnToTradingFund(amount);
    }

    // ── Admin withdraw ──────────────────────────────────────────────
    function withdrawAdmin(address to, uint256 amount) external onlyAdmin nonReentrant {
        require(to != address(0), "Zero address");
        require(amount > 0, "Zero amount");
        require(usdt.transfer(to, amount), "Transfer failed");
        emit AdminWithdraw(to, amount);
    }


    // ── Approve payout contracts to spend Vault USDT ────────────────
    function approvePayoutContract(address contractAddr, uint256 amount) external {
        require(msg.sender == owner || accessControl.isAdmin(msg.sender), "Not admin");
        require(usdt.approve(contractAddr, amount), "Approve failed");
    }

    // ── View functions ──────────────────────────────────────────────
    function getUserPositionCount(address user) external view returns (uint256) {
        return positionCount[user];
    }

    function getPosition(address user, uint256 posId)
        external
        view
        returns (
            uint256 amount,
            uint256 startTime,
            uint256 lockDays,
            uint8 tier,
            uint8 packageType,
            bool active,
            bool isGranted
        )
    {
        Position storage p = positions[user][posId];
        return (p.amount, p.startTime, p.lockDays, p.tier, p.packageType, p.active, p.isGranted);
    }

    function getVaultBalance() external view returns (uint256) {
        return usdt.balanceOf(address(this));
    }
}

